sql:
SELECT avg_wkly_wage
FROM employment_data
WHERE fips_code = 1 AND period = '1';

SELECT AVG(avg_wkly_wage) AS average_weekly_wage
FROM employment_data
WHERE total_employment = (
  SELECT MAX(total_employment)
  FROM employment_data
);

SELECT area_name, population 
FROM areas 
WHERE fips_code = 0;

external_knowledge:
- 'thriving areas' refers to areas with high employment (total_employment > 5000) and positive employment growth (employment_growth_rate > 0); 
- 'seen better days' implies a long history or multiple records for the area (COUNT(ed.fips_code) > 1); 
- 'recent times' refers to the most recent period (p.period_id = (SELECT MAX(period_id) FROM periods)); 
- 'sizable workforce' means an area with more than 5000 employees (ed.total_employment > 5000); 
- 'proven track record' refers to areas with multiple records or a long history (COUNT(ed.fips_code) > 1).
